      // Filter buttons
      function buildFilterButtons() {
  const row = document.getElementById("filterRow");
  const mapBar = document.getElementById("mapFilterBar");

  // MAP: With reel button first
  const reelWrap = document.createElement("div");
  reelWrap.className = "map-filter-wrap";
  const reelBtn = document.createElement("button");
  reelBtn.className = "map-filter-btn map-reel-filter";
  reelBtn.innerHTML = "🎥 With reel";
  reelBtn.onclick = () => {
    if (reelBtn.classList.contains("active")) {
      reelBtn.classList.remove("active");
      currentMapReelFilter = false;
      renderMapMarkers(currentMapCat);
      return;
    }
    reelBtn.classList.add("active");
    currentMapReelFilter = true;
    renderMapMarkers(currentMapCat);
  };
  mapBar.appendChild(reelWrap);
  reelWrap.appendChild(reelBtn);

  // MAP: Province dropdown second
  const mPW = document.createElement("div");
  mPW.style.cssText = "flex-shrink:0;";
  const mPS = document.createElement("select");
  mPS.className = "province-select";
  mPS.id = "mapProvinceSelect";
  const defOpt = document.createElement("option");
  defOpt.value = "all";
  defOpt.textContent = "🌍 All provinces";
  mPS.appendChild(defOpt);
  ALL_PROVINCES.forEach((p) => {
    const count = GARDENS.filter((g) => g.province === p).length;
    const opt = document.createElement("option");
    opt.value = p;
    opt.textContent = `${p} (${count})`;
    mPS.appendChild(opt);
  });
  mPS.addEventListener("change", () => {
    mPS.classList.toggle("active", mPS.value !== "all");
    currentMapProvince = mPS.value;
    renderMapMarkers(currentMapCat);
  });
  mPW.appendChild(mPS);
  mapBar.appendChild(mPW);

  // MAP: Visual separator
  const sep = document.createElement("div");
  sep.style.cssText = "width:1px;height:20px;background:rgba(255,255,255,0.2);flex-shrink:0;margin:0 4px;";
  mapBar.appendChild(sep);

  // Categories for both list and map
  ALL_CATS.forEach((cat) => {
    const ih = ICONS[cat] ? `<img src="${ICONS[cat]}" alt="">` : "";
    const lbl = cat.replace(" Gardens", "").replace(" & Sculpture", "");
    const desc = CAT_DESC[cat] || "";

    // List row
    const w = document.createElement("div");
    w.className = "filter-btn-wrap";
    const b = document.createElement("button");
    b.className = "filter-btn";
    b.dataset.cat = cat;
    b.innerHTML = `${ih}${lbl}`;
    if (desc) {
      const t = document.createElement("div");
      t.className = "cat-tooltip";
      t.textContent = desc;
      w.appendChild(t);
    }
    w.appendChild(b);
    row.appendChild(w);

    // Map bar
    const mw = document.createElement("div");
    mw.className = "map-filter-wrap";
    const mb = document.createElement("button");
    mb.className = "map-filter-btn";
    mb.innerHTML = `${ih}${lbl}`;
    mb.onclick = () => filterMap(mb, cat);
    if (desc) {
      const mt = document.createElement("div");
      mt.className = "map-cat-tooltip";
      mt.textContent = desc;
      mw.appendChild(mt);
    }
    mw.appendChild(mb);
    mapBar.appendChild(mw);
  });
}

      // Tabs
      let fullMapInit = false;
      function switchTab(tab) {
        document
          .querySelectorAll(".panel")
          .forEach((p) => p.classList.remove("active"));
        document
          .querySelectorAll(".tab-btn")
          .forEach((b) => b.classList.remove("active"));
        document.getElementById(tab + "Panel").classList.add("active");
        document.getElementById("tab-" + tab).classList.add("active");
        // Hide only the mini map frame on map tab, keep the rest of the hero
        document.querySelector(".hero-map-frame").style.display =
          tab === "map" ? "none" : "";
        if (tab === "map" && !fullMapInit) {
          initFullMap();
          fullMapInit = true;
        }
        if (tab === "map" && fullMap)
          setTimeout(() => fullMap.invalidateSize(), 50);
      }

      // Maps
      function addNLOutline(map, fillOpacity) {
        fetch(
          "https://raw.githubusercontent.com/datasets/geo-countries/master/data/countries.geojson",
        )
          .then((r) => r.json())
          .then((data) => {
            const nl = data.features.find(
              (f) =>
                f.properties.ISO_A2 === "NL" ||
                f.properties.name === "Netherlands",
            );
            if (nl)
              L.geoJSON(nl, {
                style: {
                  color: "#4a6b4e",
                  weight: 1.5,
                  fillColor: "#dde8dd",
                  fillOpacity,
                },
              }).addTo(map);
          })
          .catch(() => {});
      }
      function initMiniMap() {
        const map = L.map("miniMap", {
          zoomControl: true,
          scrollWheelZoom: true,
          dragging: true,
          doubleClickZoom: true,
          touchZoom: true,
          attributionControl: false,
          zoomSnap: 0.1,
        }).setView([52.25, 5.3], 6.8);
        L.tileLayer(
          "https://{s}.basemaps.cartocdn.com/light_nolabels/{z}/{x}/{y}{r}.png",
          { maxZoom: 19 },
        ).addTo(map);
        addNLOutline(map, 0.45);
        GARDENS.forEach((g) => {
          const iu = ICONS[g.category];
          const m = iu
            ? L.marker([g.lat, g.lng], {
                icon: L.icon({
                  iconUrl: iu,
                  iconSize: [20, 20],
                  iconAnchor: [10, 10],
                }),
              })
            : L.marker([g.lat, g.lng], {
                icon: L.divIcon({
                  className: "",
                  html: `<div style="width:10px;height:10px;border-radius:50%;background:${CAT_COLORS[g.category] || "#7a9e7e"};border:2px solid #fff;box-shadow:0 1px 4px rgba(0,0,0,.25);cursor:pointer;"></div>`,
                  iconSize: [10, 10],
                  iconAnchor: [5, 5],
                }),
              });
          m.addTo(map)
            .bindTooltip(g.name, {
              permanent: false,
              direction: "top",
              offset: [0, -5],
            })
            .on("click", () => openSheet(g));
          miniMapMarkers.push({ marker: m, g });
        });
      }
      let fullMap, markersLayer;
      function initFullMap() {
        fullMap = L.map("fullMap").setView([52.25, 5.3], 7);
        L.tileLayer(
          "https://{s}.basemaps.cartocdn.com/light_nolabels/{z}/{x}/{y}{r}.png",
          { attribution: "© OpenStreetMap © CARTO", maxZoom: 19 },
        ).addTo(fullMap);
        L.tileLayer(
          "https://{s}.basemaps.cartocdn.com/light_only_labels/{z}/{x}/{y}{r}.png",
          { maxZoom: 19 },
        ).addTo(fullMap);
        addNLOutline(fullMap, 0.15);
        markersLayer = L.layerGroup().addTo(fullMap);
        renderMapMarkers("all");
      }
      let currentMapCat = "all",
        currentMapProvince = "all",
        currentMapReelFilter = false;
      function renderMapMarkers(filter) {
        currentMapCat = filter;
        markersLayer.clearLayers();
        let list =
          filter === "all"
            ? GARDENS
            : filter === "reel"
              ? GARDENS.filter((g) => g.has_reel)
              : GARDENS.filter((g) => g.category === filter);
        if (currentMapReelFilter) list = list.filter((g) => g.has_reel);
        if (currentMapProvince !== "all")
          list = list.filter((g) => g.province === currentMapProvince);
        list.forEach((g) => {
          const sz = g.featured ? 28 : 22;
          const iu = ICONS[g.category];
          const m = iu
            ? L.marker([g.lat, g.lng], {
                icon: L.icon({
                  iconUrl: iu,
                  iconSize: [sz, sz],
                  iconAnchor: [sz / 2, sz / 2],
                }),
              })
            : L.marker([g.lat, g.lng], {
                icon: L.divIcon({
                  className: "",
                  html: `<div style="width:${sz}px;height:${sz}px;border-radius:50%;background:${CAT_COLORS[g.category] || "#7a9e7e"};border:2.5px solid #fff;box-shadow:0 2px 6px rgba(0,0,0,.22);cursor:pointer;"></div>`,
                  iconSize: [sz, sz],
                  iconAnchor: [sz / 2, sz / 2],
                }),
              });
          m.addTo(markersLayer).on("click", () => openSheet(g));
        });
      }
      function filterMap(btn, cat) {
        if (btn.classList.contains("active") && cat !== "all") {
          document
            .querySelectorAll(".map-filter-btn")
            .forEach((b) => b.classList.remove("active"));
          document
            .querySelectorAll(".map-filter-btn")[0]
            .classList.add("active");
          renderMapMarkers("all");
          return;
        }
        document
          .querySelectorAll(".map-filter-btn")
          .forEach((b) => b.classList.remove("active"));
        btn.classList.add("active");
        renderMapMarkers(cat);
      }

      // Gallery
      let galleryInstances = {};
      function initGallery(containerId, photos) {
        const container = document.getElementById(containerId);
        if (!container || !photos || !photos.length) return;
        const h = container.offsetHeight || 300;
        container.innerHTML = `
    <div class="photo-blur-bg" id="${containerId}-bg" style="background-image:url(${photos[0]})"></div>
    <div class="photo-slides" id="${containerId}-slides">
      ${photos.map((p) => `<div class="photo-slide" style="height:${h}px"><img src="${p}" alt="" loading="lazy"></div>`).join("")}
    </div>
    ${photos.length > 1 ? `<div class="photo-dots">${photos.map((_, i) => `<div class="photo-dot-g ${i === 0 ? "active" : ""}" onclick="galleryGoTo('${containerId}',${i})"></div>`).join("")}</div><div class="photo-count">1 / ${photos.length}</div>` : ""}`;
        let cur = 0;
        galleryInstances[containerId] = {
          cur,
          photos,
          goTo: (idx) => {
            cur = idx;
            galleryInstances[containerId].cur = idx;
            const s = document.getElementById(containerId + "-slides");
            const bg = document.getElementById(containerId + "-bg");
            const cnt = container.querySelector(".photo-count");
            const dots = container.querySelectorAll(".photo-dot-g");
            if (s) s.style.transform = `translateX(-${idx * 100}%)`;
            if (bg) bg.style.backgroundImage = `url(${photos[idx]})`;
            if (cnt) cnt.textContent = `${idx + 1} / ${photos.length}`;
            dots.forEach((d, i) => d.classList.toggle("active", i === idx));
          },
        };
        let sx = null;
        container.addEventListener(
          "touchstart",
          (e) => {
            sx = e.touches[0].clientX;
          },
          { passive: true },
        );
        container.addEventListener("touchend", (e) => {
          if (sx === null) return;
          const dx = e.changedTouches[0].clientX - sx;
          if (Math.abs(dx) > 40) {
            if (dx < 0 && cur < photos.length - 1)
              galleryInstances[containerId].goTo(cur + 1);
            else if (dx > 0 && cur > 0)
              galleryInstances[containerId].goTo(cur - 1);
          }
          sx = null;
        });
        let mx = null,
          drag = false;
        container.addEventListener("mousedown", (e) => {
          mx = e.clientX;
          drag = false;
        });
        container.addEventListener("mousemove", (e) => {
          if (mx !== null && Math.abs(e.clientX - mx) > 5) drag = true;
        });
        container.addEventListener("mouseup", (e) => {
          if (mx === null) return;
          const dx = e.clientX - mx;
          if (drag && Math.abs(dx) > 40) {
            if (dx < 0 && cur < photos.length - 1)
              galleryInstances[containerId].goTo(cur + 1);
            else if (dx > 0 && cur > 0)
              galleryInstances[containerId].goTo(cur - 1);
          }
          mx = null;
          drag = false;
        });
      }
      function galleryGoTo(id, idx) {
        if (galleryInstances[id]) galleryInstances[id].goTo(idx);
      }

      // Bottom sheet
      function openSheet(g) {
        const photos = GARDEN_PHOTOS[g.name] || null;
        const iconSrc = ICONS[g.category] || "";
        const reelBadge = "";
        const sheetTop = document.getElementById("sheetTop");
        if (photos && photos.length) {
          sheetTop.innerHTML = `
      <div class="photo-gallery sheet-gallery" id="sheetGallery" style="height:300px"></div>
      <div class="sheet-subheader cat-${g.category.replace(/ & /g, "-").replace(/ /g, "-")}">
        ${iconSrc ? `<img class="sheet-subheader-icon" src="${iconSrc}" alt="">` : ""}
        <div class="sheet-header-text">${reelBadge}<div class="sheet-name">${g.name}</div><div class="sheet-cat">${g.category}</div></div>
        <button class="sheet-close" onclick="closeSheet()">✕</button>
      </div>`;
        } else {
          sheetTop.innerHTML = `
      <div class="sheet-no-photo-header cat-${g.category.replace(/ & /g, "-").replace(/ /g, "-")}">
        ${iconSrc ? `<img class="sheet-header-icon" src="${iconSrc}" alt="">` : ""}
        <div class="sheet-header-text">${reelBadge}<div class="sheet-name">${g.name}</div><div class="sheet-cat">${g.category}</div></div>
        <button class="sheet-close" onclick="closeSheet()">✕</button>
      </div>`;
        }
        let lh = "";
        if (g.reel_link)
          lh += `<a class="sheet-link reel" href="${g.reel_link}" target="_blank" rel="noopener noreferrer">🎥 ${g.reel_label || "Instagram Reel"}</a>`;
        if (g.visitor_link)
          lh += `<a class="sheet-link visit" href="${g.visitor_link}" target="_blank" rel="noopener noreferrer">📍 Google Maps</a>`;
        if (!lh)
          lh =
            '<span class="sheet-no-link">Search the name in Google Maps to find it</span>';
        document.getElementById("sheetLinks").innerHTML = lh;
        document.getElementById("sheetDesc").textContent =
          g.description || g.preview || "No description available yet.";
        const sheet = document.getElementById("bottomSheet");
        sheet.style.display = "block";
        sheet.style.animation = "slideUp .32s cubic-bezier(.32,.72,0,1)";
        document.getElementById("backdrop").classList.add("open");
        document.body.style.overflow = "hidden";
        if (photos && photos.length)
          requestAnimationFrame(() => initGallery("sheetGallery", photos));
      }
      function closeSheet() {
        const sheet = document.getElementById("bottomSheet");
        sheet.style.animation = "slideDown .25s ease";
        setTimeout(() => {
          sheet.style.display = "none";
          document.getElementById("backdrop").classList.remove("open");
          document.body.style.overflow = "";
        }, 230);
      }
      document.addEventListener("keydown", (e) => {
        if (e.key === "Escape") closeSheet();
      });

      // Featured
      function renderFeatured(list) {
        const section = document.getElementById("featuredSection");
        const scroll = document.getElementById("featuredScroll");
        const featured = list.filter((g) => g.featured);
        if (!featured.length) {
          section.style.display = "none";
          return;
        }
        section.style.display = "";
        scroll.innerHTML =
          featured
            .map((g) => {
              const photos = GARDEN_PHOTOS[g.name] || null;
              const ih = ICONS[g.category]
                ? `<img class="fc-icon" src="${ICONS[g.category]}" alt="">`
                : "";
              const safeG = JSON.stringify(g).replace(/"/g, "&quot;");
              const rb = g.reel_link
                ? `<a class="fc-link reel" href="${g.reel_link}" target="_blank" rel="noopener noreferrer">🎥 ${g.reel_label || "Instagram Reel"}</a>`
                : "";
              const vb = g.visitor_link
                ? `<a class="fc-link visit" href="${g.visitor_link}" target="_blank" rel="noopener noreferrer">📍 Google Maps</a>`
                : "";
              const pc = photos
                ? `<div class="gc-photo-circle"><img src="${photos[0]}" alt=""></div>`
                : "";
              return `<article class="featured-card" data-garden="${safeG}">
      <div class="fc-header cat-${g.category.replace(/ & /g, "-").replace(/ /g, "-")}">${pc}<div class="fc-name" style="padding-right:${photos ? "70px" : "28px"}">${g.name}</div><div class="fc-header-top">${ih}<span class="fc-cat">${g.category}</span></div></div>
      ${rb || vb ? `<div class="fc-links">${rb}${vb}</div>` : ""}
      <div class="fc-body">${g.preview ? `<p class="fc-desc">${g.preview}</p>` : ""}<span class="fc-hint">Tap to read more →</span></div>
    </article>`;
            })
            .join("") + '<div class="fc-spacer"></div>';
        // Dots
        const dots = document.getElementById("scrollDots");
        // Build dots after a tick so scroll dimensions are known
        setTimeout(() => {
          const cw = scroll.querySelector(".featured-card");
          if (!cw) return;
          const cardW = cw.offsetWidth + 16;
          const total = featured.length;
          // How many cards are actually reachable by scrolling
          const maxScroll = scroll.scrollWidth - scroll.clientWidth;
          const reachable =
            window.innerWidth <= 780
              ? total
              : Math.min(total, Math.floor(maxScroll / cardW) + 1);
          // Build dots based on reachable count
          dots.innerHTML = Array.from(
            { length: reachable },
            (_, i) =>
              `<div class="scroll-dot ${i === 0 ? "active" : ""}" data-i="${i}"></div>`,
          ).join("");
          // Helper: last dot always scrolls to true end
          function targetFor(i) {
            return i >= reachable - 1 ? maxScroll : i * cardW;
          }
          // Dot click handlers
          dots.querySelectorAll(".scroll-dot").forEach((d) =>
            d.addEventListener("click", () => {
              scroll.scrollTo({
                left: targetFor(+d.dataset.i),
                behavior: "smooth",
              });
            }),
          );
          // Scroll listener - update dots, loop back to start
          let isJumping = false;
          let userScrolling = false;
          let userScrollTimer = null;
          scroll.addEventListener("scroll", () => {
            if (isJumping) return;
            const pos = scroll.scrollLeft;
            const cur = Math.round(pos / cardW);
            dots
              .querySelectorAll(".scroll-dot")
              .forEach((d, j) =>
                d.classList.toggle(
                  "active",
                  j === Math.min(cur, reachable - 1),
                ),
              );
            if (false) {
              isJumping = true;
              scroll.scrollTo({ left: 0, behavior: "instant" });
              setTimeout(() => (isJumping = false), 100);
            }
          });
          // Autoscroll
          let autoTimer = setInterval(advance, 3500);
          function advance() {
            const cur = Math.round(scroll.scrollLeft / cardW);
            const next = cur + 1 >= reachable ? 0 : cur + 1;
            scroll.scrollTo({ left: targetFor(next), behavior: "smooth" });
          }
          function pauseAuto() {
            userScrolling = true;
            clearInterval(autoTimer);
            clearTimeout(userScrollTimer);
          }
          function resumeAuto() {
            userScrollTimer = setTimeout(() => {
              userScrolling = false;
              autoTimer = setInterval(advance, 3500);
            }, 2000);
          }
          scroll.addEventListener("mouseenter", () => pauseAuto());
          scroll.addEventListener("mouseleave", () => resumeAuto());
          scroll.addEventListener("touchstart", () => pauseAuto(), {
            passive: true,
          });
          scroll.addEventListener("touchend", () => resumeAuto(), {
            passive: true,
          });
        }, 500);
        scroll.addEventListener("mousedown", (e) => {
          sx = e.pageX - scroll.offsetLeft;
          sl = scroll.scrollLeft;
          scroll.style.cursor = "grabbing";
        });
        scroll.addEventListener(
          "mouseleave",
          () => (scroll.style.cursor = "grab"),
        );
        scroll.addEventListener(
          "mouseup",
          () => (scroll.style.cursor = "grab"),
        );
        scroll.addEventListener("mousemove", (e) => {
          if (!e.buttons) return;
          e.preventDefault();
          scroll.scrollLeft = sl - (e.pageX - scroll.offsetLeft - sx);
        });
      }

      // Grid
      function renderAll(list) {
        const grid = document.getElementById("gardensGrid");
        const empty = document.getElementById("emptyState");
        const nf = list.filter((g) => !g.featured);
        if (!list.length) {
          grid.innerHTML = "";
          empty.style.display = "block";
          return;
        }
        empty.style.display = "none";
        grid.innerHTML = nf
          .map((g) => {
            const ih = ICONS[g.category]
              ? `<img class="gc-icon" src="${ICONS[g.category]}" alt="">`
              : "";
            const safeG = JSON.stringify(g).replace(/"/g, "&quot;");
            const rb = g.reel_link
              ? `<a class="gc-link reel" href="${g.reel_link}" target="_blank" rel="noopener noreferrer">🎥 ${g.reel_label || "Instagram Reel"}</a>`
              : "";
            const vb = g.visitor_link
              ? `<a class="gc-link visit" href="${g.visitor_link}" target="_blank" rel="noopener noreferrer">📍 Google Maps</a>`
              : "";
            const lb = rb || vb ? `<div class="gc-links">${rb}${vb}</div>` : "";
            const photos = GARDEN_PHOTOS[g.name];
            const pc = photos
              ? `<div class="gc-photo-circle"><img src="${photos[0]}" alt=""></div>`
              : "";
            return `<article class="garden-card" data-garden="${safeG}">
    <div class="gc-header cat-${g.category.replace(/ & /g, "-").replace(/ /g, "-")}">${pc}<div class="gc-name" style="padding-right:${photos ? "70px" : "14px"}">${g.name}</div><div class="gc-header-top">${ih}<span class="gc-cat-label">${g.category}</span></div></div>
      ${lb}
      ${g.preview ? `<div class="gc-body"><p class="gc-preview">${g.preview}</p></div>` : ""}
    </article>`;
          })
          .join("");
      }

      function updateCount(n) {
        document.getElementById("resultsCount").textContent =
          n === GARDENS.length ? `${n} gardens` : `${n} of ${GARDENS.length}`;
      }

      let currentFilter = "all",
        currentSearch = "",
        currentProvince = "all",
        currentReelFilter = false;
      let miniMapMarkers = [];
      function updateMiniMapFilter(list) {
        if (!miniMapMarkers.length) return;
        const visibleNames = new Set(list.map((g) => g.name));
        miniMapMarkers.forEach(({ marker, g }) => {
          const el = marker.getElement();
          if (el) el.style.opacity = visibleNames.has(g.name) ? "1" : "0.12";
        });
      }
      function applyFilters() {
        const q = currentSearch.toLowerCase().trim();
        let list = [...GARDENS];
        if (currentFilter === "reel") list = list.filter((g) => g.has_reel);
        else if (currentFilter !== "all")
          list = list.filter((g) => g.category === currentFilter);
        if (currentReelFilter) list = list.filter((g) => g.has_reel);
        if (currentProvince !== "all")
          list = list.filter((g) => g.province === currentProvince);
        if (q)
          list = list.filter(
            (g) =>
              g.name.toLowerCase().includes(q) ||
              g.category.toLowerCase().includes(q) ||
              (g.preview || "").toLowerCase().includes(q),
          );
        renderFeatured(list);
        renderAll(list);
        updateCount(list.length);
        updateMiniMapFilter(list);
      }
      document.getElementById("filterRow").addEventListener("click", (e) => {
        const btn = e.target.closest(".filter-btn");
        if (!btn) return;
        if (btn.classList.contains("active") && btn.dataset.cat !== "all") {
          document
            .querySelectorAll(".filter-btn")
            .forEach((b) => b.classList.remove("active"));
          document
            .querySelector('.filter-btn[data-cat="all"]')
            .classList.add("active");
          currentFilter = "all";
          applyFilters();
          return;
        }
        document
          .querySelectorAll(".filter-btn")
          .forEach((b) => b.classList.remove("active"));
        btn.classList.add("active");
        currentFilter = btn.dataset.cat;
        applyFilters();
      });
      document.querySelector(".reel-filter").addEventListener("click", (e) => {
        const btn = e.target.closest(".filter-btn");
        if (!btn) return;
        if (btn.classList.contains("active")) {
          btn.classList.remove("active");
          currentReelFilter = false;
          applyFilters();
          return;
        }
        btn.classList.add("active");
        currentReelFilter = true;
        applyFilters();
      });
      document.getElementById("filterRow").addEventListener(
        "touchstart",
        (e) => {
          const wrap = e.target.closest(".filter-btn-wrap");
          if (!wrap) return;
          const tooltip = wrap.querySelector(".cat-tooltip");
          if (!tooltip) return;
          document.querySelectorAll(".cat-tooltip").forEach((t) => {
            t.style.display = "none";
            t.style.position = "";
            t.style.top = "";
            t.style.left = "";
            t.style.transform = "";
          });
          const rect = wrap.getBoundingClientRect();
          tooltip.style.position = "fixed";
          tooltip.style.top = rect.bottom + 8 + "px";
          tooltip.style.left =
            Math.min(rect.left, window.innerWidth - 230) + "px";
          tooltip.style.transform = "none";
          tooltip.style.display = "block";
          setTimeout(() => {
            tooltip.style.display = "none";
            tooltip.style.position = "";
            tooltip.style.top = "";
            tooltip.style.left = "";
            tooltip.style.transform = "";
          }, 2500);
        },
        { passive: true },
      );
      document.getElementById("searchInput").addEventListener("input", (e) => {
        currentSearch = e.target.value;
        applyFilters();
      });

      // INIT
      buildFilterButtons();
      buildProvinceDropdown();
      applyFilters();
      initMiniMap();

      // Fix tooltip overflow on both browse and map filter bars
      function fixTooltipOverflow(wrapSelector, tooltipSelector) {
        document.querySelectorAll(wrapSelector).forEach((wrap) => {
          wrap.addEventListener("mouseenter", () => {
            const tooltip = wrap.querySelector(tooltipSelector);
            if (!tooltip) return;
            // Reset first
            tooltip.style.left = "";
            tooltip.style.right = "";
            tooltip.style.transform = "translateX(-50%)";
            const rect = tooltip.getBoundingClientRect();
            const pad = 8;
            if (rect.left < pad) {
              // Bleeding off left
              const shift = pad - rect.left;
              tooltip.style.left = "calc(50% + " + shift + "px)";
              tooltip.style.transform = "translateX(-50%)";
            } else if (rect.right > window.innerWidth - pad) {
              // Bleeding off right
              const shift = rect.right - (window.innerWidth - pad);
              tooltip.style.left = "calc(50% - " + shift + "px)";
              tooltip.style.transform = "translateX(-50%)";
            }
          });
        });
      }
      document.addEventListener("DOMContentLoaded", () => {
        fixTooltipOverflow(".filter-btn-wrap", ".cat-tooltip");

        // Position map tooltips using fixed coords to escape overflow clipping
        function positionMapTooltip(wrap, tooltip) {
          const rect = wrap.getBoundingClientRect();
          const ttW = 200;
          let left = rect.left + rect.width / 2 - ttW / 2;
          left = Math.max(8, Math.min(left, window.innerWidth - ttW - 8));
          tooltip.style.width = ttW + "px";
          tooltip.style.left = left + "px";
          tooltip.style.top = rect.bottom + 10 + "px";
        }

        // Hover positioning for map tooltips on desktop
        document.querySelectorAll(".map-filter-wrap").forEach((wrap) => {
          const tooltip = wrap.querySelector(".map-cat-tooltip");
          if (!tooltip) return;
          wrap.addEventListener("mouseenter", () => {
            tooltip.style.display = "block";
            positionMapTooltip(wrap, tooltip);
          });
          wrap.addEventListener("mouseleave", () => {
            tooltip.style.display = "";
          });
        });

        // Touch tap-to-toggle tooltips (mobile)
        if (window.matchMedia("(hover: none)").matches) {
          const style = document.createElement("style");
          style.textContent =
            ".filter-btn-wrap:hover .cat-tooltip, .map-filter-wrap:hover .map-cat-tooltip { display: none; }";
          document.head.appendChild(style);

          function closeAllTooltips() {
            document
              .querySelectorAll(".cat-tooltip, .map-cat-tooltip")
              .forEach((t) => (t.style.display = ""));
          }

          function addTouchTooltip(wrapSelector, tooltipSelector) {
            document.querySelectorAll(wrapSelector).forEach((wrap) => {
              const tooltip = wrap.querySelector(tooltipSelector);
              if (!tooltip) return;
              let startX = 0;
              let startY = 0;
              wrap.addEventListener(
                "touchstart",
                (e) => {
                  startX = e.touches[0].clientX;
                  startY = e.touches[0].clientY;
                },
                { passive: true },
              );
              wrap.addEventListener(
                "touchend",
                (e) => {
                  const dx = Math.abs(e.changedTouches[0].clientX - startX);
                  const dy = Math.abs(e.changedTouches[0].clientY - startY);
                  if (dx > 8 || dy > 8) return; // swipe, not a tap
                  const isOpen = tooltip.style.display === "block";
                  closeAllTooltips();
                  if (!isOpen) {
                    tooltip.style.display = "block";
                    if (tooltipSelector === ".map-cat-tooltip") {
                      positionMapTooltip(wrap, tooltip);
                    } else {
                      fixTooltipOverflow(wrapSelector, tooltipSelector);
                    }
                    e.stopPropagation();
                  }
                },
                { passive: true },
              );
            });
          }

          addTouchTooltip(".filter-btn-wrap", ".cat-tooltip");
          addTouchTooltip(".map-filter-wrap", ".map-cat-tooltip");

          document.addEventListener("touchstart", closeAllTooltips, {
            passive: true,
          });
        }

        // Handle all card and link clicks via delegation
        ["gardensGrid", "featuredScroll"].forEach((id) => {
          const el = document.getElementById(id);
          if (!el) return;
          el.addEventListener("click", (e) => {
            // If a link button was clicked, let the browser follow it, don't open sheet
            const link = e.target.closest(".gc-link, .fc-link");
            if (link) return;
            // Otherwise open the sheet for the card
            const card = e.target.closest("[data-garden]");
            if (card) {
              try {
                openSheet(
                  JSON.parse(card.dataset.garden.replace(/&quot;/g, '"')),
                );
              } catch (err) {}
            }
          });
        });
      });
